Thanks for the great library!

I have been using pybind for our open source project. One of the useful feature we are using is binding Numpy array to ``std::vector<Eigen::Vector3d>``. For example,
```
import numpy as np
import time

from pybind11_tests import stl_eigen as m

class Timer(object):
    def __init__(self, name=None):
        self.name = name

    def __enter__(self):
        self.tstart = time.time()

    def __exit__(self, type, value, traceback):
        if self.name:
            print('[%s]' % self.name)
        print('Elapsed: %.3f' % (time.time() - self.tstart))

def test_stl_eigen():
    with Timer("Test Vector3dVector"):
        x = np.random.random((2000000,3))
        y = m.Vector3dVector(x)
``` 
in ``test_stl_eigen()`` function, `y` gets ``std::vector<Eigen::Vector3d>``. 

The issue I would like to mention is related to the time. We have been using pybind since 2.0_dev version. With pybind 2.0 dev, ``test_stl_eigen`` took about 0.3s. With stable release pybind 2.2 or higher, ``test_stl_eigen`` took about 2.3s. Could I ask some help from pybind community?

For your reference, here is the cpp code we wrote for binding.
```
#include "pybind11_tests.h"
#include "constructor_stats.h"
#include <pybind11/eigen.h>
#include <pybind11/stl.h>
#include <pybind11/stl_bind.h>
#include <pybind11/numpy.h>
#include <pybind11/operators.h>
#include <pybind11/functional.h>

namespace pybind11 {

template <typename Vector, typename holder_type = std::unique_ptr<Vector>, typename... Args>
pybind11::class_<Vector, holder_type> bind_vector_without_repr(
        pybind11::module &m, std::string const &name, Args&&... args) {
    // hack function to disable __repr__ for the convenient function
    // bind_vector()
    using Class_ = pybind11::class_<Vector, holder_type>;
    Class_ cl(m, name.c_str(), std::forward<Args>(args)...);
    cl.def(pybind11::init<>());
    pybind11::detail::vector_if_copy_constructible<Vector, Class_>(cl);
    pybind11::detail::vector_if_equal_operator<Vector, Class_>(cl);
    pybind11::detail::vector_modifiers<Vector, Class_>(cl);
    pybind11::detail::vector_accessor<Vector, Class_>(cl);
    cl.def("__bool__", [](const Vector &v) -> bool {
        return !v.empty();
    }, "Check whether the list is nonempty");
    cl.def("__len__", &Vector::size);
    return cl;
}

template <typename EigenVector>
void pybind_eigen_vector_of_vector(py::module &m, const std::string &bind_name,
        const std::string &repr_name)
{
    typedef typename EigenVector::Scalar Scalar;
    auto vec = py::bind_vector_without_repr<std::vector<EigenVector>>(
            m, bind_name, py::buffer_protocol());
    vec.def_buffer([](std::vector<EigenVector> &v) -> py::buffer_info {
        size_t rows = EigenVector::RowsAtCompileTime;
        return py::buffer_info(
                v.data(), sizeof(Scalar),
                py::format_descriptor<Scalar>::format(),
                2, {v.size(), rows},
                {sizeof(EigenVector), sizeof(Scalar)});
    });
    vec.def("__repr__", [repr_name](const std::vector<EigenVector> &v) {
        return repr_name + std::string(" with ") +
                std::to_string(v.size()) + std::string(" elements.\n") +
                std::string("Use numpy.asarray() to access data.");
    });
    vec.def("__copy__", [](std::vector<EigenVector> &v) {
        return std::vector<EigenVector>(v);
    });
    vec.def("__deepcopy__", [](std::vector<EigenVector> &v) {
        return std::vector<EigenVector>(v);
    });
}

}

TEST_SUBMODULE(stl_eigen, m) {
    pybind11::pybind_eigen_vector_of_vector<Eigen::Vector3d>(m, "Vector3dVector",
            "std::vector<Eigen::Vector3d>");
}
```

Firstly, thank you for this wonderful library. As I was using it I found some unexpected/undesired behaviour. Wrapped function objects from std::functional will copy the result even when the result is of type pointer.
Here is my sample code to reproduce the issue.
```c++
#include <functional>
#include <pybind11/pybind11.h>
#include <pybind11/functional.h>

namespace py = pybind11;

struct Test {
    Test() {};
    Test(const Test &obj) = delete;
    int i;
};
Test* fullFunction()
{
    return new Test();
}
std::function<Test*(void)> func = &fullFunction;

PYBIND11_MODULE(example, m) {
    // optional module docstring
    m.attr("full") = py::cpp_function(func);
    m.attr("func") = func;
    py::class_<Test>(m,"Test")
        .def_readwrite("i",&Test::i);
}
```
```python
import example
example.full()
example.func()
```
example.func() will result in an error: return_value_policy = copy, but the object is non-copyable!

It's my understanding that both full & func should return a Test* and that the underlying Test will not be copied however when the pybind11/functional wrapper handles it, it will attempt to copy Test*. I believe this occurs because a function object is an object and not a pointer which causes copy to be the default behaviour that is detected. Sorry if I have misunderstood anything.

Dear Pybind11 Developers, I noticed that on Mac(apple clang) platform attempts to bind any of `std::basic_*stream::gcount` methods lead to a linking error `illegal text reloc`. Interestingly attempts to bind any other methods of these class group seems to work just fine. 

Also, this error is only appears on Mac+clang and the code works just fine on Linux. 

Any idea of what might be wrong here?

Thanks,

Minimal example to reproduce:
```C++
// Require Mac OS X + Clang to reproduce
#include <pybind11/pybind11.h>
#include <iostream>

namespace py = pybind11;

PYBIND11_PLUGIN(example)
{
    py::module m("example", "pybind11 example plugin");

	pybind11::class_<std::basic_istream<char,std::char_traits<char>> > cl(m, "basic_istream_char_std_char_traits_char_t", "");

	//cl.def("gcount", &std::basic_istream<char, std::char_traits<char> >::gcount);
	// uncommenting the line above will lead to ld error: illegal text reloc in '_initexample' to '__ZNKSt3__113basic_istreamIcNS_11char_traitsIcEEE6gcountEv' for architecture x86_64

	cl.def("get", (int (std::basic_istream<char,std::char_traits<char>>::*)()) &std::basic_istream<char, std::char_traits<char> >::get);

    return m.ptr();
}
```

Nice work on this encoder.

Looking at the documentation for [quantisation](https://github.com/tilezen/mapbox-vector-tile#quantization), it states that:

> When encoding, pass in the bounds in the form (minx, maxx, miny, maxy) and the coordinates will be scaled appropriately during encoding.

The following example then has:

```python
mapbox_vector_tile.encode([
      {
        "name": "water",
        "features": [
          {
            "geometry":"POINT(15 15)",
            "properties":{
              "foo":"bar",
            }
          }
        ]
      }
    ], quantize_bounds=(10.0, 10.0, 20.0, 20.0))
```
Those bounds look like minx, miny, maxx, maxy, and indeed the source code:

```python
def quantize(self, shape, bounds):
        minx, miny, maxx, maxy = bounds
```

Easy fix that only affects that bit of documentation in the readme.

Start Python with `RAY_USE_XRAY=1 ipython`

```python
import ray

ray.init(num_cpus=4)

@ray.remote(num_cpus=1)
class Foo:
    def method(self):
        pass

fs = [Foo.remote() for _ in range(4)]

ray.get([x.method.remote() for x in f])  # This succeeds

@ray.remote
class Bar:
    def method(self):
        pass

b = Bar.remote()

ray.get(b.method.remote())  # This hangs
```

